def bitmap(pg):
    return pg.Bitmap(DATA, WIDTH, HEIGHT, format=FORMAT, palette=PALETTE,
                     frames=FRAMES, stride=STRIDE, transparent=TRANSPARENT)

def build(pg, tileset):
    tm = pg.Tilemap(tileset, COLS, ROWS)
    for y in range(ROWS):
        for x in range(COLS):
            v = CELLS[y * COLS + x]
            if v & 0x0f:
                tm.tile(x, y, v & 0x0f, flip_x=bool(v & 0x10),
                        flip_y=bool(v & 0x20), transpose=bool(v & 0x40))
    return tm
